```cpp
#include <stdexcept>
#include <limits>

template<typename T>
T safe_access(T* arr, size_t size, int index) {
    if (arr == nullptr) {
        throw std::invalid_argument("数组指针为空");
    }
    if (index < 0 || index >= static_cast<int>(size)) {
        throw std::out_of_range("索引越界");
    }
    return arr[index];
}
```

